mapper.select:
select r.* from biz_instrument_open_rule r inner join biz_instrument i on i.id = r.instrument_id and i.deleted = 0 where r.deleted = 0
and i.owner_user_id = #{operatorId}
and i.department_id = #{scopeDepartmentId}
order by r.instrument_id asc, r.week_day asc, r.start_time asc


select r.*
from biz_instrument_open_rule r
left join biz_instrument i on i.id = r.instrument_id and i.deleted = 0
where r.deleted = 0

  and r.instrument_id = #{instrumentId}


  and (
    r.week_day = #{weekDay}
    or (r.week_days is not null and r.week_days != '' and find_in_set(cast(#{weekDay} as char), r.week_days) > 0)
  )


  and r.status = #{status}


  and i.owner_user_id = #{operatorId}


  and i.department_id = #{scopeDepartmentId}

order by r.update_time desc, r.id desc
limit #{offset}, #{pageSize}


select count(1)
from biz_instrument_open_rule r
left join biz_instrument i on i.id = r.instrument_id and i.deleted = 0
where r.deleted = 0

  and r.instrument_id = #{instrumentId}


  and (
    r.week_day = #{weekDay}
    or (r.week_days is not null and r.week_days != '' and find_in_set(cast(#{weekDay} as char), r.week_days) > 0)
  )


  and r.status = #{status}


  and i.owner_user_id = #{operatorId}


  and i.department_id = #{scopeDepartmentId}

mapper.insert:
insert into biz_instrument_open_rule(
  instrument_id, week_day, week_days, start_time, end_time, max_reserve_minutes, step_minutes,
  effective_start_date, effective_end_date, status, create_time, update_time, deleted
) values (
  #{instrumentId}, #{weekDay}, #{weekDays}, #{startTime}, #{endTime}, #{maxReserveMinutes}, #{stepMinutes},
  #{effectiveStartDate}, #{effectiveEndDate}, #{status}, #{createTime}, #{updateTime}, #{deleted}
)

mapper.update:
update biz_instrument_open_rule
set deleted = 1, update_time = #{updateTime}
where instrument_id = #{instrumentId} and deleted = 0
